#include<bits/stdc++.h>
using namespace std;
vector<int>v[1005];
int a[1005][1005];
int main()
{
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int x,y;
		cin>>x>>y;
		v[x].push_back(y);
		v[y].push_back(x);
		a[x][y]=1;
		a[y][x]=1;
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cout<<a[i][j]<<" ";
		}
		cout<<endl;
	}
	//cout<<endl;
	for(int i=1;i<=n;i++){
		cout<<v[i].size()<<" ";
		sort(&v[i][0],&v[i][v[i].size()]);
		for(int j=0;j<v[i].size();j++){
			cout<<v[i][j]<<" ";
		}
		cout<<endl;
	}
}
